solution_code:
#include <iostream>

int scale(int n)
{
    return n * 4;
}

int shift(int n)
{
    return n + 3;
}

int main()
{
    int n;
    std::cin >> n;
    std::cerr << "input: " << n << "\n";
    int after_scale = scale(n);
    std::cerr << "after scale: " << after_scale << "\n";
    int result = shift(after_scale);
    std::cerr << "after shift: " << result << "\n";
    std::cout << result << "\n";
    return 0;
}

