solution_code:
#include <iostream>

int multiply(int a, int b)
{
    return a * b;
}

int combine(int product, int b)
{
    return product + b;
}

int main()
{
    int a;
    int b;
    std::cin >> a >> b;
    std::cerr << "a=" << a << " b=" << b << "\n";
    int product = multiply(a, b);
    std::cerr << "product=" << product << "\n";
    std::cout << combine(product, b) << "\n";
    return 0;
}
